INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-00491', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員於判斷某項風險是否為顯著風險時，不應考量下列何項因素？', '["交易之複雜程度", "與該項風險有關之控制所能降低風險之效果", "該風險是否與最近之重大經濟、會計或其他事件有關，而須特別關注", "與該風險有關之財務資訊衡量之主觀程度，特別是不確定性較高之衡量"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00492', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關內部控制之敘述，下列何者錯誤？', '["董事會對內部控制制度之態度係控制環境之一環", "擬定生產計畫、制定領料、投入、成本計算等政策及程序係屬控制作業", "母公司控制作業應包括對子公司之監督與管理等政策及程序", "公司規模與控制作業有效性成正比"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00493', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '查核人員瞭解受查者電腦系統一般控制時，最不可能採用下列那一項程序？', '["檢查電腦系統相關的文件", "查詢受查者員工", "對一筆銷貨交易執行穿透測試（walkthroughtest）", "複核受查者資訊系統員工填寫的問卷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00494', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關集團財務報表查核，下列敘述何者錯誤？', '["如集團主辦會計師擬於集團查核報告中提及組成個體查核人員之查核，則應通知組成個體 查核人員", "如集團主辦會計師擬於集團查核報告中指明組成個體主辦會計師之姓名或所屬事務所，則 應取得其同意，且該組成個體之查核報告須與集團查核報告一併列報", "如組成個體之主辦會計師對組成個體財務報表出具修正式意見之查核報告，集團查核團隊 經評估此事項對集團查核報告之可能影響後，集團主辦會計師得出具無保留意見之集團查 核報告", "組成個體與集團適用之財務報導架構不同時，集團主辦會計師應於集團查核報告中敘明組 成個體查核人員負有評估財務報導架構轉換調整適當性之責任"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00495', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據審計準則公報第63號「首次受託查核案件—期初餘額」之規定，下列敍述何者錯誤？', '["會計師如無法對期初餘額取得足夠及適切之查核證據，則應出具保留意見或無法表示意見 之查核報告", "會計師如推斷期初餘額存有重大影響本期財務報表之不實表達，且其影響未適當處理、表 達或揭露，則應出具保留意見或否定意見之查核報告", "會計師如發現期初餘額所適用之會計政策未依適用之財務報導架構，並於本期繼續採用， 則應出具附強調事項段之無保留意見查核報告", "會計師如發現會計政策變動，但未依適用之財務報導架構適當處理、表達或揭露，則應出 具保留意見或否定意見之查核報告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00496', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關會計估計與相關揭露之查核，下列敘述何者錯誤？', '["會計估計之估計不確定性不致使查核人員對受查者繼續經營之能力產生重大疑慮", "估計不確定性之程度受會計估計之性質影響", "例行性交易有關之會計估計其重大不實表達風險較低", "使用非普遍接受之衡量技術計算之會計估計可能存有顯著風險"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00497', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關核閱財務報表，下列敘述何者錯誤？', '["財務報表之核閱，對財務報表是否在所有重大方面係依照適用之財務報導架構編製及允當 表達，無法提供表示意見之基礎", "核閱並非用以對財務報表未存有重大不實表達取得合理確信", "核閱時所執行之程序包括查詢（主要向受核閱者負責財務與會計事務之人員查詢）、分析性 程序及其他核閱程序，但通常不用執行風險評估程序", "會計師應對個別核閱案件執行適用之品質管制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00498', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '下列那些情況較可能造成會計估計之估計不確定性提高？①會計估計對假設改變較敏感', '["查核人員未採用專家工作", "會計估計之預測期間較長", "外部可靠資料無法取得  ⑤會 計估計帳載金額較大  ⑥使用受查者自行開發之特殊模型", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 16, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00499', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '依據審計準則公報第66號「書面聲明」之規定，下列敘述何者正確？', '["書面聲明自身無法對所涉及之事項提供足夠及適切之查核證據，因此非必要查核證據", "書面聲明之日期應儘量接近查核報告日，但不得早於該日。書面聲明應涵蓋查核報告中提 及之所有財務報表與期間", "於某些情況下，管理階層可能於書面聲明中使用「就本公司所知」之限制性文字", "書面聲明不可靠或未取得之可能影響係屬廣泛，而非僅侷限於財務報表之特定要素或項目， 此時會計師應出具保留意見之查核報告"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00500', 'cpa', 'cpa-moex-110-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '甲公司針對某具有高度不確性之衍生性工具之公允價值作出單一金額之會計估計，以前年度 並無評估經驗及設置必要之控制，甲公司亦未針對該等會計估計之不確定性予以適當處理， 經查核人員評估此公允價值之衡量具顯著風險，則最有可能選擇下列何項額外證實程序以為 因應？', '["確定截至查核報告日發生之事項是否提供有關會計估計之查核證據", "測試管理階層如何作會計估計及其所依據之資料", "測試與會計估計相關控制執行之有效性，並執行適當之證實程序", "建立金額區間估計以評估管理階層單一金額估計"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:06+00:00", "source_pdf_sha1": "63d2fcb4aaa6", "answer_pdf_sha1": "142833232a16", "source_family": "moex-gov-tw", "moex": {"exam_code": "110140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "110", "exam_name": "110年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL)
